<script setup>
import { onMounted, ref } from "vue";

const svgContainer = ref(null);

onMounted(async () => {
  if (typeof window === "undefined") return;

  // Dynamically import svg-pan-zoom on the client only to avoid SSR issues
  const mod = await import("svg-pan-zoom");
  const svgPanZoom = mod.default || mod;

  // We target the SVG element inside our ref container
  const svgElement = svgContainer.value.querySelector("svg");

  if (svgElement) {
    svgPanZoom(svgElement, {
      zoomEnabled: true,
      controlIconsEnabled: true,
      fit: true,
      center: true,
    });
  }
});
</script>

